public class Delivery {
    private DeliveryStatus status = DeliveryStatus.CREATED;
    private LocalDateTime dispatchedAt;
    private LocalDateTime deliveredAt;

    public void dispatch() {
        if (status != DeliveryStatus.CREATED) {
            throw new IllegalStateException("Solo se puede despachar una entrega CREATED");
        }
        this.status = DeliveryStatus.DISPATCHED;
        this.dispatchedAt = LocalDateTime.now();
    }

    public void deliver() {
        if (status != DeliveryStatus.IN_TRANSIT) {
            throw new IllegalStateException("Solo se puede entregar si está IN_TRANSIT");
        }
        this.status = DeliveryStatus.DELIVERED;
        this.deliveredAt = LocalDateTime.now();
    }

    public DeliveryStatus getStatus() { return status; }
}
